import{_ as t,o,c as r,a3 as n}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"69H. Workers Compensation Rehabilitation And Return To Work","description":"","frontmatter":{"title":"69H. Workers Compensation Rehabilitation And Return To Work","eba":"Mental Health Services 2024-2028","topics":["ohs","workers-comp"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/ohs/69H-workers-compensation-rehabilitation-and-return-to-work.md","filePath":"ebas/mental-health/common-terms/ohs/69H-workers-compensation-rehabilitation-and-return-to-work.md"}'),a={name:"ebas/mental-health/common-terms/ohs/69H-workers-compensation-rehabilitation-and-return-to-work.md"};function i(s,e,p,l,h,m){return o(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="_69h-workers-compensation-rehabilitation-and-return-to-work" tabindex="-1">69H. Workers Compensation Rehabilitation And Return To Work <a class="header-anchor" href="#_69h-workers-compensation-rehabilitation-and-return-to-work" aria-label="Permalink to &quot;69H. Workers Compensation Rehabilitation And Return To Work&quot;">​</a></h1><p><strong>69H.1</strong> Workers Compensation Information</p><p><strong>(a)</strong> The Employer will display and make available the WorkSafe Victoria &quot;If You Are Injured at Work&quot; Poster, as amended from time to time.</p><p><strong>(b)</strong> The Employer will provide a copy of the poster (A4 version) to Employees as soon as they report an incident that may give rise to an injury to themselves.</p><p><strong>69H.2</strong> Attendance at medical appointments</p><p><strong>(a)</strong> Where there is an accepted workers&#39; compensation claim, an Employee who requires time off during work time to attend medical and other appointments may elect to:</p><p><strong>(i)</strong> take the time as paid personal leave (subject to having sufficient accrued leave); or</p><p><strong>(ii)</strong> take the time as paid work time, in which case the Employer may claim repayment for that time under workers&#39; compensation legislation, subject to that legislation</p><p><strong>69H.3</strong> Return to Work</p><p><strong>(a)</strong> This clause shall apply to an employee not performing their normal duties due to a work- related injury to which the WIRC Act applies.</p><p><strong>(b)</strong> The Employer will appoint a Return-to-Work Co-ordinator who will have sufficient knowledge of occupational rehabilitation legislation, regulations and guidelines to undertake the task.</p><p><strong>(c)</strong> The Employer will develop an appropriate return to work plan as soon as medically appropriate in consultation with the injured Employee concerned, their treating doctor and health professionals providing treatment or services to the injured Employee.</p><p><strong>(d)</strong> The Employer will assist injured Employees to remain at work or return to work in suitable employment as soon as medically appropriate after injury. The Employer will ensure that the suitable employment will reflect and be commensurate with, as far as possible, the skills, education, age, experience, pre-injury employment, and any relevant medical restrictions of the injured Employee. The suitable employment will also take into account the Employee&#39;s place of residence and pre-injury hours of work.</p><p><strong>(e)</strong> Without limiting the content of the return-to-work plan, the plan will include, but not be limited to a return-to-work program signed by the Employer, Employee and treating doctor which covers:</p><p><strong>(i)</strong> the estimated date of the return to work</p><p><strong>(ii)</strong> the position title</p><p><strong>(iii)</strong> the duties and hours of work to be offered</p><p><strong>(iv)</strong> the nature of the incapacity and any medical restrictions</p><p><strong>(v)</strong> the applicable classification and pay rate</p><p><strong>(vi)</strong> steps to be taken to facilitate the return to work; and</p><p><strong>(vii)</strong> the date or dates for regular review.</p><p><strong>(f)</strong> The return-to-work plan may also consider:</p><p><strong>(i)</strong> subject to approval by the insurer, any personal and household services required, including modifications to the home or car, household help, counselling, aids or appliances, transportation costs, etc; and</p><p><strong>(ii)</strong> subject to approval by the insurer, any occupational rehabilitation services, including modifications to the workplace, home or car which will apply, equipment to be provided at the workplace, etc.</p><p><strong>(g)</strong> The return-to-work plan will be reviewed at least monthly or more regularly as needed, in consultation with the injured Employee and other relevant parties.</p><p><strong>(h)</strong> Employees will have the right to have a representative present at any interview arranged by their Employer regarding their return to work or rehabilitation, including monitoring or review of their return-to-work program. When arranging such interviews, the Employer will advise the Employee that they may have a representative present. The Employer will where practicable provide to the Employee at least seven days&#39; notice of such interviews occurring.</p><p><strong>(i)</strong> The Employer will not seek to change the Employee&#39;s duties, hours or other aspects of the Employee&#39;s employment or return to work plan without consulting with the Employee.</p><p><strong>(j)</strong> A Union representative may be involved in any negotiations or discussions regarding any such proposed changes, at the request of the Employee.</p><p><strong>(k)</strong> The Employer and the Employee will co-operate and participate in the agreed return to work plan. This plan will be reviewed at the request of any of the parties involved. Where agreement cannot be reached the processes of the WIRC Act will apply.</p><p><strong>69H.4</strong> Rehabilitation, Re-training and Re-education</p><p><strong>(a)</strong> The Employer may pay for any re-training or re-education which is required to assist the Employee to remain at work or return to work in suitable employment in accordance with guidelines issued by Victorian WorkSafe to its agents. Approval for such re-training or re- education may be requested by the Employee, their treating practitioner, or any other Victorian WorkSafe approved service provider, individual or agency, on behalf of the Employee.</p><p><strong>(b)</strong> Where it has been established that an Employee has a permanent injury or condition which prevents them returning to their pre injury employment the Employer will ensure the Employee is advised of all vacancies as they become available.</p>',32)])])}const u=t(a,[["render",i]]);export{d as __pageData,u as default};
